<?php
require_once __DIR__ . '/../includes/academy-header.php'; require_learner();
$courseId=(int)($_GET['course'] ?? $_POST['course_id'] ?? 0); $course=get_course($pdo,$courseId); if(!$course){ exit('Course not found'); } enroll_learner($pdo, learner_id(), $courseId); $quiz=get_quiz($pdo,$courseId); if(!$quiz){ exit('Quiz not found'); } $result=null;
if($_SERVER['REQUEST_METHOD']==='POST' && verify_csrf($_POST['csrf_token'] ?? null)){ $score=0; $answers=[]; foreach($quiz['questions'] as $q){ $ans=(string)($_POST['q_'.$q['id']] ?? ''); $answers[$q['id']]=$ans; if($ans===$q['correct_option']) $score++; } $total=count($quiz['questions']); $percent=$total ? (int)round(($score/$total)*100) : 0; $passed=$percent >= (int)$quiz['pass_mark']; $stmt=$pdo->prepare('INSERT INTO quiz_attempts (learner_id,course_id,quiz_id,score,total_questions,percentage,passed,answers) VALUES (:l,:c,:q,:s,:t,:p,:pass,:a)'); $stmt->execute([':l'=>learner_id(),':c'=>$courseId,':q'=>$quiz['id'],':s'=>$score,':t'=>$total,':p'=>$percent,':pass'=>$passed?1:0,':a'=>json_encode($answers)]); if($passed && eligible_for_certificate($pdo, learner_id(), $courseId)){ issue_certificate($pdo, learner_id(), $courseId); } $result=['score'=>$score,'total'=>$total,'percent'=>$percent,'passed'=>$passed,'answers'=>$answers]; }
?>
<section class="page-hero academy-page-hero"><div class="container"><p class="eyebrow">Course Quiz</p><h1><?= e($quiz['title']); ?></h1><p>Pass mark: <?= (int)$quiz['pass_mark']; ?>%. Submit your answers to see your score and the correct explanations.</p></div></section>
<section class="section-pad"><div class="container"><form class="glass-card quiz-card" method="post"><input type="hidden" name="csrf_token" value="<?= e(csrf_token()); ?>"><input type="hidden" name="course_id" value="<?= $courseId; ?>"><?php if($result): ?><div class="alert <?= $result['passed']?'alert-success':'alert-danger'; ?>">Score: <?= $result['percent']; ?>% (<?= $result['score']; ?>/<?= $result['total']; ?>). <?= $result['passed']?'Passed.':'Keep learning and try again.'; ?></div><?php endif; ?><?php foreach($quiz['questions'] as $i=>$q): ?><div class="quiz-question"><h3><?= $i+1; ?>. <?= e($q['question']); ?></h3><?php foreach(['A'=>'option_a','B'=>'option_b','C'=>'option_c','D'=>'option_d'] as $letter=>$field): ?><label class="quiz-option"><input type="radio" name="q_<?= (int)$q['id']; ?>" value="<?= $letter; ?>" required> <span><?= $letter; ?>. <?= e($q[$field]); ?></span></label><?php endforeach; ?><?php if($result): ?><p class="result">Correct answer: <?= e($q['correct_option']); ?>. <?= e($q['explanation']); ?></p><?php endif; ?></div><?php endforeach; ?><button class="btn btn-premium btn-lg" type="submit">Submit Quiz</button><a class="btn btn-outline-light btn-lg" href="certificate.php?course=<?= $courseId; ?>">View Certificate</a></form></div></section>
<?php include __DIR__ . '/../includes/academy-footer.php'; ?>